const subject = $json.subject || '';
const isDigestSubject = /YouTube Crypto Digest/i.test(subject);

if (!isDigestSubject) {
  return { json: { isDigestReply: false, reason: 'subject did not match', subject } };
}

// Normalize line endings first -- CRLF (\r\n) is common in real email bodies, and a leftover trailing \r breaks regex $ anchors and . matching (both treat \r as a line terminator).
const text = ($json.textPlain || '').replace(/\r\n/g, '\n').replace(/\r/g, '\n');
const lines = text.split('\n');

let boundary = lines.length;
for (let i = 0; i < lines.length; i++) {
  const l = lines[i].trim();
  if (/^On .+wrote:$/.test(l) || l.startsWith('>')) {
    boundary = i;
    break;
  }
}

const replyBody = lines.slice(0, boundary).join('\n').trim();
const quoted = lines.slice(boundary).map(l => l.replace(/^>\s?/, '')).join('\n');

const numMatch = replyBody.match(/\b([1-5])\b/);
const selectedNum = numMatch ? numMatch[1] : null;

const videoMap = {};
const qLines = quoted.split('\n');
for (let i = 0; i < qLines.length; i++) {
  const m = qLines[i].match(/^\s*(\d+)\.\s+(.+)$/);
  if (m) {
    const num = m[1];
    const title = m[2].trim();
    let url = null;
    for (let j = i + 1; j < qLines.length && j < i + 3; j++) {
      const urlMatch = qLines[j].match(/(https?:\/\/\S+)/);
      if (urlMatch) { url = urlMatch[1]; break; }
    }
    videoMap[num] = { title, url };
  }
}

const selected = selectedNum ? videoMap[selectedNum] : null;

if (!selected || !selected.url) {
  return {
    json: {
      isDigestReply: false,
      reason: 'could not resolve a selected video from the reply',
      selectedNumber: selectedNum,
      videoMap,
      replyBody,
      rawTextPlain: text,
    }
  };
}

return {
  json: {
    isDigestReply: true,
    selectedNumber: selectedNum,
    selectedTitle: selected.title,
    selectedUrl: selected.url,
    videoMap,
    replyBody,
  }
};

const url = $json.selectedUrl || '';
const patterns = [
  /(?:youtube\.com\/watch\?v=|youtu\.be\/|youtube\.com\/embed\/|youtube\.com\/shorts\/)([a-zA-Z0-9_-]{11})/
];
let videoId = null;
for (const p of patterns) {
  const m = url.match(p);
  if (m) { videoId = m[1]; break; }
}

return {
  json: {
    ...$json,
    videoId,
    watchUrl: videoId ? ('https://www.youtube.com/watch?v=' + videoId) : null,
  }
};

const html = $json.data || '';
const videoTitle = $('Parse Reply & Select Video').item.json.selectedTitle;
const videoUrl = $('Parse Reply & Select Video').item.json.selectedUrl;

const match = html.match(/"captionTracks":(\[.*?\])(?=,")/) || html.match(/"captionTracks":(\[.*?\])/);
if (!match) {
  return { json: { transcriptAvailable: false, captionUrl: '', videoTitle, videoUrl } };
}

let tracks;
try {
  tracks = JSON.parse(match[1]);
} catch (e) {
  return { json: { transcriptAvailable: false, captionUrl: '', videoTitle, videoUrl } };
}

const track = tracks.find(t => t.languageCode === 'en')
  || tracks.find(t => (t.languageCode || '').startsWith('en'))
  || tracks[0];

if (!track || !track.baseUrl) {
  return { json: { transcriptAvailable: false, captionUrl: '', videoTitle, videoUrl } };
}

const captionUrl = track.baseUrl.replace(/\\u0026/g, '&');
return { json: { transcriptAvailable: true, captionUrl, videoTitle, videoUrl } };

const xml = $json.data || '';
const prev = $('Extract Caption Track URL').item.json;
const videoTitle = prev.videoTitle;
const videoUrl = prev.videoUrl;
const transcriptAvailable = prev.transcriptAvailable;

function decodeEntities(s) {
  return s
    .replace(/&amp;/g, '&')
    .replace(/&#39;/g, "'")
    .replace(/&quot;/g, '"')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>');
}

if (!transcriptAvailable || !xml || !xml.includes('<text')) {
  return {
    json: {
      transcript: '(No auto-captions were available for this video. Article will be based on the title only -- expect a thin draft, review carefully.)',
      videoTitle,
      videoUrl,
      hasTranscript: false,
    }
  };
}

const matches = [...xml.matchAll(/<text[^>]*>([\s\S]*?)<\/text>/g)];
const decoded = matches
  .map(m => decodeEntities(m[1]))
  .join(' ')
  .replace(/\s+/g, ' ')
  .trim();

return {
  json: {
    transcript: (decoded || '(Transcript was empty after parsing.)').slice(0, 12000),
    videoTitle,
    videoUrl,
    hasTranscript: decoded.length > 0,
  }
};

