const raw = $json.choices[0].message.content;
let parsed;
try {
  const cleaned = raw.trim().replace(/^```json\n?/, '').replace(/```$/, '');
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    title: 'Draft: ' + $('Parse Transcript XML').item.json.videoTitle,
    content: raw,
  };
}
return { json: parsed };

const resp = $json;
const prev = $('Extract Caption Track URL').item.json;
const videoTitle = prev.videoTitle;
const videoUrl = prev.videoUrl;

const segments = resp && resp.transcript;
if (!Array.isArray(segments) || segments.length === 0) {
  return {
    json: {
      transcript: '(No auto-captions were available and the TranscriptAPI fallback found no transcript for this video -- likely a genuinely caption-less or private/removed video. Article will be based on the title only -- expect a thin draft, review carefully.)',
      videoTitle,
      videoUrl,
      hasTranscript: false,
    }
  };
}

const text = segments.map(s => s.text).join(' ').replace(/\s+/g, ' ').trim();

return {
  json: {
    transcript: (text || '(Transcript was empty after parsing.)').slice(0, 12000),
    videoTitle,
    videoUrl,
    hasTranscript: text.length > 0,
  }
};
